var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기가…… 소문의 그곳. 맞나요?","JPN":"ここが……あの噂の、ですね？","ENG":"Is this... where the rumors are all about?","TWN":"請問……這裡是傳說中的那個地方嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마, 마담?!","JPN":"マ、マダム！？","ENG":"M-madam?!","TWN":"夫…夫人？！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여긴 어떻게……!","JPN":"どうしてここに……！","ENG":"H-how did you...?!","TWN":"您怎麼會來……！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"소문을 듣고 찾아왔죠. 당신들이 악몽을 없애 준다는 그분들인가요?","JPN":"噂を聞いて来たのです。あなたたちが悪夢を消してくれるという方々ですか？","ENG":"I came after hearing all the rumors, of course. Are you the one who gets rid of nightmares?","TWN":"當然是因為聽到傳言，才找到這裡來的囉～你們就是可以幫人消除惡夢的人嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……저 누군지 모르세요?","JPN":"……私のこと、ご存じありませんか？","ENG":"...You don’t know who I am?","TWN":"……您不知道我是誰嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"정말…… 제가 누군지 모른다고요?","JPN":"本当に……私が誰なのか知らないんですか？","ENG":"Are you sure... you don’t know me?","TWN":"您真的……不認得我嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"미안해요. 나이가 드니 자꾸 깜빡하게 되네?","JPN":"ごめんなさいね。歳のせいか、うっかりしちゃうの。","ENG":"I’m sorry. Age has made my memories a little foggy.","TWN":"不好意思，上年紀後記性退步不少呢。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가…….","JPN":"そんなわけ……","ENG":"No way...","TWN":"怎麼會……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그보다 여기.","JPN":"それより、はい。","ENG":"Anyway...","TWN":"話說，"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"얼만지는 얘기를 안 해주길래 넉넉히 챙겨 왔어요.","JPN":"いくらなのか教えてもらえなかったので、たっぷり持ってきました。","ENG":"No one told me what you charged, so I brought more than enough.","TWN":"我不知道這裡的收費，所以有多帶一點來。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"한…… 이 정도?","JPN":"そうね……このくらい？","ENG":"About... this much?","TWN":"差不多……這樣？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이, 이렇게나 많이요?!","JPN":"こ、こんなにですか！？","ENG":"Th-this much?!","TWN":"這…這麼多？！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"혹시 부족한가요? 더 챙겨 왔어야 됐나……?","JPN":"もしかして足りませんか？　もっと持ってくるべきだったかしら……？","ENG":"Is it not enough? Should I have brought more?","TWN":"夠嗎？還是要再多帶一點……？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……하, 하하! 아닙니다. 이 정도면 충분해요!","JPN":"……は、はは！　いいえ。これで十分ですよ！","ENG":"Hah... Hah hah! Not at all! This is more than enough!","TWN":"……哈哈哈！夠夠夠！非常夠！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"제가 아는 누구랑 너~무 닮으셔서 잠시 착각했나 봐요.","JPN":"私の知ってる人にあまりにも似てて、ちょっと勘違いしてしまったようです。","ENG":"You resemble someone I know, and I must’ve confused you for her.","TWN":"我剛好像認錯人，因為您長得和我認識的一個人很～像。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래서 어떤 고민으로 오셨나요, 손님?","JPN":"それで、お悩みはなんですか？　お客様。","ENG":"So, what brings you here, ma’am?","TWN":"好的，這位客人，您有什麼煩惱嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 제가 요즘 통 잠을 못 자서…… 악몽에 깨는 일이 많거든요.","JPN":"ふぅ。この頃、どうしても眠れなくて……悪夢で目覚める時が多いのです。","ENG":"*Sigh...* I haven’t been able to get a good night’s rest... These nightmares keep waking me up, you see.","TWN":"哀，我最近都睡不好……老是從惡夢中驚醒過來。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제가 맡은 일이 많기도 하고, 제게 의지하는 사람도 많고.","JPN":"担当している仕事も多いですし、私に頼る人もたくさんいるんです。","ENG":"I have many responsibilities, and many people rely on me.","TWN":"我要負責很多事，而且很多人都依賴我。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};